// spotless:off
package frc.robot.generated;

import edu.wpi.first.math.geometry.Pose2d;
import edu.wpi.first.math.geometry.Rotation2d;
import java.util.OptionalInt;

/**
 * Trajectory constants for the Shoot-and-Climb autonomous routines.
 *
 * These are manually authored (generated via Python trapezoidal profile) and stored
 * here — NOT in ChoreoTraj.java — because ChoreoTraj.java is auto-regenerated by the
 * Choreo Gradle plugin from ChoreoProject.chor and would overwrite manual additions.
 *
 * To edit these paths, open Choreo, load the corresponding .traj file from
 * src/main/deploy/choreo/, adjust waypoints, re-solve, save, then update the
 * duration/start/end values below to match.
 */
@SuppressWarnings("unused")
public final class ShootAndClimbTraj {

    private ShootAndClimbTraj() {}

    public static final ChoreoTraj Right = new ChoreoTraj(
        "ShootAndClimbTrajectory_Right",
        OptionalInt.empty(),
        2.067,
        new Pose2d(3.598, 0.640, Rotation2d.fromRadians(3.14159)),
        new Pose2d(0.941, 3.564, Rotation2d.fromRadians(3.14159))
    );

    public static final ChoreoTraj Center = new ChoreoTraj(
        "ShootAndClimbTrajectory_Center",
        OptionalInt.empty(),
        1.649,
        new Pose2d(3.598, 4.036, Rotation2d.fromRadians(3.14159)),
        new Pose2d(0.941, 3.564, Rotation2d.fromRadians(3.14159))
    );

    public static final ChoreoTraj Left = new ChoreoTraj(
        "ShootAndClimbTrajectory_Left",
        OptionalInt.empty(),
        2.314,
        new Pose2d(3.598, 7.432, Rotation2d.fromRadians(3.14159)),
        new Pose2d(0.941, 3.564, Rotation2d.fromRadians(3.14159))
    );
}
